solution_code:
#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int counter;
    int flag;
} Shared;

int main(void) {
    Shared *shm = (Shared *)calloc(1, sizeof(Shared));
    printf("counter=%d flag=%d\n", shm->counter, shm->flag);
    shm->counter = 7;
    shm->flag = 1;
    printf("counter=%d flag=%d\n", shm->counter, shm->flag);
    free(shm);
    return 0;
}

