typedef struct { int counter; int flag; } Shared;

/* == EXEMPLE ===============================================
 * calloc zero-init : struct Stats avec reads et writes
 * calloc garantit que tous les champs valent 0 au demarrage.
 * ========================================================= */
typedef struct { int reads; int writes; } Stats;

void example_calloc_stats(void) {
    Stats *st = (Stats *)calloc(1, sizeof(Stats));
    printf("reads=%d writes=%d\n", st->reads, st->writes);
    st->reads = 15;
    st->writes = 3;
    printf("reads=%d writes=%d\n", st->reads, st->writes);
    free(st);
}
/* Resultat: reads=0 writes=0 puis reads=15 writes=3 */

